effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);
const vec3 uniformWeighting = vec3(0.3333, 0.3334, 0.3333);

void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    float luma = weighted ? length(texColor.rgb * luminanceWeighting) : length(texColor.rgb * uniformWeighting);
    //float alpha = smoothstep( threshold-feather/2., threshold+feather/2., length(texColor.rgb) );
    float lowThresholdA = clamp(lowThreshold-feather/2.,0.,1.);
    float lowThresholdB = clamp(lowThresholdA+feather,0.,1.);
    float highThresholdA = clamp(highThreshold-feather/2.,0.,1.);
    float highThresholdB = clamp(highThresholdA+feather,0.,1.);
    float lowBlend = smoothstep( lowThresholdA, lowThresholdB, luma );
    float highBlend = 1. - smoothstep( highThresholdA, highThresholdB, luma );
    float alpha = min(lowBlend,highBlend);
    if(invert) alpha = 1.-alpha;
    gl_FragColor = texColor*alpha;
}
